import { json, type RequestHandler } from '@sveltejs/kit';

export const POST: RequestHandler = async ({ request }) => {
    try {
        // 🔹 Parse request body
        const body = await request.json();
        console.log('📩 Received request:', body);

        const { prompt, model_id, project_id } = body;

        const API_URL = 'https://eu-gb.ml.cloud.ibm.com/ml/v1/text/generation?version=2023-05-29';
        const API_KEY = import.meta.env.VITE_IAM_API_KEY;

        console.log('IBM_API_KEY:', API_KEY ? 'Loaded' : 'Missing');

        if (!API_KEY) {
            console.error('❌ Error: IBM API key is missing');
            return json({ error: 'API key is missing' }, { status: 500 });
        }

        // 🟢 Step 1: Get IBM Cloud token
        console.log('🔄 Requesting IBM token...');
        const tokenResponse = await fetch('https://iam.cloud.ibm.com/identity/token', {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: `grant_type=urn:ibm:params:oauth:grant-type:apikey&apikey=${API_KEY}`
        });

        const tokenData = await tokenResponse.json();
        // console.log('🔑 Token Response:', tokenData);

        if (!tokenResponse.ok || !tokenData.access_token) {
            throw new Error(`Token error: ${tokenResponse.status} - ${tokenData.error_description || 'Unknown error'}`);
        }

        const { access_token } = tokenData;
        console.log('✅ IBM Token acquired.');

        // 🟢 Step 2: Call IBM Cloud AI API
        const requestBody = {
            input: prompt,
            parameters: {
                decoding_method: 'greedy',
                max_new_tokens: 900,
                min_new_tokens: 0,
                stop_sequences: [],
                repetition_penalty: 1
            },
            model_id,
            project_id
        };

        console.log('📤 Sending request to IBM API:', JSON.stringify(requestBody, null, 2));

        const response = await fetch(API_URL, {
            method: 'POST',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${access_token}`
            },
            body: JSON.stringify(requestBody)
        });

        const responseData = await response.json();
        console.log('📩 IBM API Response:', responseData);

        if (!response.ok) {
            throw new Error(`IBM Cloud API error: ${response.status} - ${responseData.error || 'Unknown error'}`);
        }

        return json(responseData);
    } catch (error: any) {
        console.error('❌ Error:', error.message);
        return json({ error: 'Failed to fetch data', details: error.message }, { status: 500 });
    }
};
